import { TrendingUp, Activity, Cpu, Mic } from 'lucide-react';
import { Dot } from './ds';

export default function Header({ health }) {
  const svcs = [
    { icon: Cpu,      label: 'Claude',  ok: health?.anthropic },
    { icon: Mic,      label: 'Whisper', ok: health?.openai },
    { icon: Activity, label: 'Live',    ok: true },
  ];

  return (
    <header style={{
      height: 48,
      background: 'var(--ink)',
      display: 'flex', alignItems: 'center', justifyContent: 'space-between',
      padding: '0 22px',
      flexShrink: 0,
    }}>
      {/* Wordmark */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 9 }}>
        <TrendingUp size={15} color='#fff' strokeWidth={2.5} />
        <span style={{
          fontFamily: 'var(--f-display)', fontSize: 15, color: '#fff',
          letterSpacing: '-0.01em', fontStyle: 'italic',
        }}>
          Research Terminal
        </span>
        <span style={{
          fontFamily: 'var(--f-data)', fontSize: 9.5,
          color: 'rgba(255,255,255,0.35)', letterSpacing: '0.12em',
          textTransform: 'uppercase', marginLeft: 2,
        }}>
          v2
        </span>
      </div>

      {/* Service status */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
        {svcs.map(({ icon: Icon, label, ok }) => (
          <div key={label} style={{
            display: 'flex', alignItems: 'center', gap: 6,
            fontSize: 11, fontWeight: 400,
            color: ok ? 'rgba(255,255,255,0.7)' : 'rgba(255,255,255,0.28)',
            transition: 'color 0.3s',
          }}>
            <Dot on={ok} color={ok ? '#4ade80' : 'rgba(255,255,255,0.18)'} />
            <Icon size={11} strokeWidth={1.8} />
            {label}
          </div>
        ))}
      </div>
    </header>
  );
}
